import './App.css';
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import io from 'socket.io-client';
import adImage from './adImage.png';

const socket = io('http://localhost:5001');

const App = () => {
  const [questions, setQuestions] = useState([]);
  const [category, setCategory] = useState('General');
  const [solvedQuestions, setSolvedQuestions] = useState([]);
  const [selectedAnswers, setSelectedAnswers] = useState({});

  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        const res = await axios.get('/api/questions', { params: { category } });
        setQuestions(res.data);
      } catch (error) {
        console.error('Error fetching questions:', error);
      }
    };

    const fetchSolvedState = async () => {
      try {
        // const res = await axios.get('/api/solved', {
        //   params: { userId: 'USER_ID' } // Adjust how you derive userId
        // });
        const res = await axios.get('/api/solved');
        setSolvedQuestions(res.data.solvedQuestions || []);
      } catch (error) {
        console.error('Error fetching solved state:', error);
      }
    };

    const generateQuestion = async () => {
      try {
        const response = await axios.get('/api/generate-question?category=General');
        console.log("Question generated:", response.data);
      } catch (error) {
        console.error('Error generating question:', error);
      }
    };

    generateQuestion();

    fetchQuestions();
    fetchSolvedState();

    socket.on('updateSolved', (data) => {
      setSolvedQuestions((prevState) => {
        if (!prevState.includes(data.questionId)) {
          return [...prevState, data.questionId];
        }
        return prevState;
      });
    });

    return () => {
      socket.off('updateSolved');
    };

  }, [category]);

  // const socket = io('http://localhost:5001');

  socket.on('connect', () => {
    console.log('Connected to server');
  });



  const handleCategoryChange = async (e) => {
    const newCategory = e.target.value;
    setCategory(newCategory);

    // Generate a new question for the selected category
    try {
      await axios.get(`/api/generate-question?category=${newCategory}`);
      const res = await axios.get('/api/questions', { params: { category: newCategory } });
      setQuestions(res.data);
    } catch (error) {
      console.error('Error generating or fetching questions:', error);
    }
  };


  const handleAnswerChange = (questionId, optionIndex) => {
    setSelectedAnswers({
      ...selectedAnswers,
      [questionId]: optionIndex,
    });

    const question = questions.find(q => q._id === questionId);
    // if (optionIndex === question.correct) 
    if (optionIndex === question.correct && !solvedQuestions.includes(questionId)) {
      const socket = io('http://localhost:5001');
      socket.emit('solveQuestion', { questionId }); // Adjust userId
    }

  };


  return (
    <div className="app-container">
      {/* Navigation bar */}
      <div className="navbar">
        <div className="nav-left">
          <span className="solved-counter">{`Community Solved: ${solvedQuestions.length}/${questions} `}</span>
        </div>
        <div className="nav-center">
          <select
            className='category-dropdown'
            // onChange={(e) => setCategory(e.target.value)}
            onChange={handleCategoryChange}
            value={category}
          >
            <option>Select a Category</option>
            <option value="General">General</option>
            <option value="History">History</option>
            <option value="Math">Math</option>
            <option value="Political">Political</option>
            <option value="Literature">Literature</option>
          </select>
        </div>
        <div className="nav-right">
          {/* <span className="user-welcome">Welcome, John Smith</span> */}
        </div>
      </div>

      {/* Grid container */}
      <div className="grid-container">
        {questions.map((q) => (
          <div key={q._id} className={`grid-item ${solvedQuestions.includes(q._id) ? 'correct' : ''}`}>
            <div className="ad-banner">
              <img src={adImage} alt="Advertisement" />
            </div>
            <p>{q.question}</p>
            {q.options.map((option, index) => (
              <label key={index}>
                <input
                  type="radio"
                  name={`question-${q._id}`}
                  checked={selectedAnswers[q._id] === index}
                  onChange={() => handleAnswerChange(q._id, index)}
                />
                {option}
              </label>
            ))}
          </div>
        ))}
      </div>
    </div>
  );

};


export default App;
